    val result = arr.clone()
    val n = result.length

    for (i <- 1 until n) {
      val key = result(i)
      var j = i - 1

      while (j >= 0 && result(j) > key) {
        result(j + 1) = result(j)
        j = j - 1
      }
      result(j + 1) = key
    }

    result
  }
}

